import React, { useState, useEffect } from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import { toast } from 'react-toastify';
import api from '../../utils/api';

export default function AdminUsers() {
  const [searchParams] = useSearchParams();
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState({
    role: searchParams.get('role') || '',
    status: searchParams.get('status') || '',
    page: 1,
  });
  const [total, setTotal] = useState(0);
  const [pages, setPages] = useState(1);

  const fetchUsers = async () => {
    setLoading(true);
    try {
      const params = new URLSearchParams();
      if (filters.role) params.set('role', filters.role);
      if (filters.status) params.set('status', filters.status);
      params.set('page', filters.page);
      params.set('limit', 15);
      const res = await api.get(`/users?${params}`);
      setUsers(res.data.data);
      setTotal(res.data.total);
      setPages(res.data.pages);
    } catch {
      toast.error('Failed to load users');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchUsers(); }, [filters]);

  const approveUser = async (id, name) => {
    try {
      await api.put(`/users/${id}/approve`);
      toast.success(`${name} approved`);
      fetchUsers();
    } catch (err) { toast.error(err.response?.data?.message || 'Failed'); }
  };

  const rejectUser = async (id, name) => {
    const reason = prompt(`Reason for rejecting ${name}:`);
    if (reason === null) return;
    try {
      await api.put(`/users/${id}/reject`, { reason });
      toast.success(`${name} rejected`);
      fetchUsers();
    } catch { toast.error('Failed'); }
  };

  const deleteUser = async (id, name) => {
    if (!window.confirm(`Delete user ${name}? This cannot be undone.`)) return;
    try {
      await api.delete(`/users/${id}`);
      toast.success('User deleted');
      fetchUsers();
    } catch (err) { toast.error(err.response?.data?.message || 'Failed'); }
  };

  return (
    <div className="page-wrapper">
      <div className="container">
        <div className="page-header">
          <div className="flex-between">
            <div>
              <h2 style={{ fontFamily: 'var(--font-display)', marginBottom: 4 }}>USER <span className="gradient-text">MANAGEMENT</span></h2>
              <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem' }}>{total} users found</p>
            </div>
            <Link to="/admin" className="btn btn-outline">← Dashboard</Link>
          </div>
        </div>

        {/* Filters */}
        <div style={{ display: 'flex', gap: 12, marginBottom: 24, flexWrap: 'wrap' }}>
          {[['', 'All Roles'], ['admin', 'Admin'], ['community_admin', 'Community Admin'], ['student', 'Student']].map(([v, l]) => (
            <button key={v} onClick={() => setFilters(p => ({ ...p, role: v, page: 1 }))} className={`btn btn-sm ${filters.role === v ? 'btn-primary' : 'btn-outline'}`}>{l}</button>
          ))}
          <div style={{ width: 1, background: 'var(--border)', margin: '0 4px' }} />
          {[['', 'All Status'], ['pending', 'Pending'], ['approved', 'Approved'], ['rejected', 'Rejected']].map(([v, l]) => (
            <button key={v} onClick={() => setFilters(p => ({ ...p, status: v, page: 1 }))} className={`btn btn-sm ${filters.status === v ? 'btn-primary' : 'btn-outline'}`}>{l}</button>
          ))}
        </div>

        {loading ? (
          <div className="loading-screen"><div className="spinner" /></div>
        ) : users.length === 0 ? (
          <div className="empty-state"><div className="empty-state-icon">👤</div><div>No users found</div></div>
        ) : (
          <>
            <div className="table-wrapper">
              <table>
                <thead>
                  <tr>
                    <th>USER</th>
                    <th>ROLE</th>
                    <th>STATUS</th>
                    <th>IT NUMBER</th>
                    <th>COMMUNITY</th>
                    <th>JOINED</th>
                    <th>ACTIONS</th>
                  </tr>
                </thead>
                <tbody>
                  {users.map(u => (
                    <tr key={u._id}>
                      <td>
                        <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                          <div className="avatar">{u.name?.charAt(0)}</div>
                          <div>
                            <div style={{ fontWeight: 600, fontSize: '0.875rem' }}>{u.name}</div>
                            <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>{u.email}</div>
                          </div>
                        </div>
                      </td>
                      <td><span className={`badge badge-${u.role}`}>{u.role.replace('_', ' ')}</span></td>
                      <td><span className={`badge badge-${u.status}`}>{u.status}</span></td>
                      <td><span style={{ fontFamily: 'var(--font-mono)', fontSize: '0.78rem', color: 'var(--text-secondary)' }}>{u.itNumber || '—'}</span></td>
                      <td style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>{u.managedCommunity?.name || '—'}</td>
                      <td style={{ fontSize: '0.78rem', color: 'var(--text-muted)' }}>{new Date(u.createdAt).toLocaleDateString()}</td>
                      <td>
                        <div style={{ display: 'flex', gap: 6 }}>
                          {u.status === 'pending' && (
                            <>
                              <button onClick={() => approveUser(u._id, u.name)} className="btn btn-success btn-sm">✓</button>
                              <button onClick={() => rejectUser(u._id, u.name)} className="btn btn-danger btn-sm">✗</button>
                            </>
                          )}
                          {u.role !== 'admin' && (
                            <button onClick={() => deleteUser(u._id, u.name)} className="btn btn-sm btn-outline" style={{ borderColor: 'var(--danger)', color: 'var(--danger)' }}>🗑</button>
                          )}
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            {/* Pagination */}
            {pages > 1 && (
              <div style={{ display: 'flex', gap: 8, justifyContent: 'center', marginTop: 24 }}>
                {Array.from({ length: pages }, (_, i) => i + 1).map(p => (
                  <button key={p} onClick={() => setFilters(prev => ({ ...prev, page: p }))} className={`btn btn-sm ${filters.page === p ? 'btn-primary' : 'btn-outline'}`}>{p}</button>
                ))}
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}
